#include <stdio.h>

int main(void) {
    int n;
    double sum = 1.0;

    printf("Enter an integer n: ");
    scanf("%d", &n);

    for (int i = 2; i <= n; i++) {
        double numerator = 2 * i + 1;
        double denominator = i * i - 1;
        if (i % 2 == 0) {
            sum -= numerator / denominator;
        } else {
            sum += numerator / denominator;
        }
    }

    printf("%.3f\n", sum);

    return 0;
}
